<!DOCTYPE html>
<html>
<head>
<title>Simple Desktop Environment</title>
<style>
body {
  background-color: #282c34;
  font-family: sans-serif;
  margin: 0;
  padding: 0;
}

#desktop {
  width: 100%;
  height: 100vh;
  display: grid;
  grid-template-rows: auto 1fr auto; /* Taskbar at the bottom */
}

#taskbar {
  background-color: #3e4451;
  color: white;
  padding: 10px;
  text-align: left;
  display: flex;
  justify-content: space-between;
}

.launcher {
  background-color: transparent;
  border: none;
  color: white;
  cursor: pointer;
  padding: 5px 10px;
  text-decoration: none;
}

.launcher:hover {
  background-color: rgba(255, 255, 255, 0.1);
}

#files-window, #notepad-window {
  width: 360px;
  height: 240px;
  border: 1px solid #3e4451;
  box-shadow: 0 2px 5px rgba(0, 0, 0, 0.3);
  display: flex;
  flex-direction: column;
}

.win-close {
  background-color: #dc3545;
  color: white;
  border: none;
  padding: 5px 10px;
  cursor: pointer;
  margin-top: auto;
}

.fs-item {
  padding: 5px;
  cursor: pointer;
}

.fs-item:hover {
  background-color: rgba(255, 255, 255, 0.05);
}

#files-path {
  margin-bottom: 10px;
  color: #61afef;
}

#files-up {
  background-color: #3e4451;
  color: white;
  padding: 5px 10px;
  cursor: pointer;
}

#tabs {
  display: flex;
  border-bottom: 1px solid #3e4451;
}

.tab {
  background-color: #282c34;
  color: white;
  padding: 8px 16px;
  cursor: pointer;
  flex-shrink: 0; /* Prevent tabs from shrinking */
}

.tab.active {
  background-color: #3e4451;
}

#editor {
  height: 180px;
  width: 100%;
  border: none;
  padding: 10px;
  font-family: monospace;
}

</style>
</head>
<body>

<div id="desktop">
  <div id="taskbar">
    <a href="#" class="launcher" id="open-files">Files</a>
    <a href="#" class="launcher" id="open-notepad">Notepad</a>
  </div>

  <div id="files-path">/</div>
  <div id="files-content">
    <div class="fs-item"><span onclick="navigate('/bin)">bin</span></div>
    <div class="fs-item"><span onclick="navigate('/etc')">etc</span></div>
    <div class="fs-item"><span onclick="navigate('/home')">home</span></div>
    <div class="fs-item"><span onclick="navigate('/usr')">usr</span></div>
    <div class="fs-item"><span onclick="navigate('/var')">var</span></div>
    <div class="fs-item"><span onclick="navigate('/home/user')">user</span></div>
    <div class="fs-item"><span onclick="navigate('/home/user/Documents')">Documents</span></div>
    <div class="fs-item"><span onclick="navigate('/home/user/Downloads')">Downloads</span></div>
    <div class="fs-item"><span onclick="navigate('/home/user/Pictures')">Pictures</span></div>
  </div>

  <div id="files-up"></div>
</div>

<div id="notepad-window" style="display: none;">
  <div id="tabs">
    <a href="#" class="tab" id="new-tab">New Tab</a>
  </div>
  <div id="editor" contenteditable="true"></div>
</div>


<script>
const desktop = document.getElementById('desktop');
const taskbar = document.getElementById('taskbar');
const openFilesLink = document.getElementById('open-files');
const openNotepadLink = document.getElementById('open-notepad');
const filesPathDisplay = document.getElementById('files-path');
const filesContent = document.getElementById('files-content');
const filesUpButton = document.getElementById('files-up');
const filesWindow = document.getElementById('files-window');
const notepadWindow = document.getElementById('notepad-window');
const tabs = document.getElementById('tabs');
const newTabLink = document.getElementById('new-tab');
const editor = document.getElementById('editor');

let currentPath = '/';
let currentTabIndex = 0;
let localStorageData = {};


function navigate(path) {
  currentPath = path;
  filesPathDisplay.textContent = currentPath;
  if (path === '/') {
    filesContent.innerHTML = '';
    const rootItems = ['bin', 'etc', 'home', 'usr', 'var'];
    rootItems.forEach(item => {
      const itemElement = document.createElement('div');
      itemElement.classList.add('fs-item');
      itemElement.onclick = () => navigate('/' + item);
      itemElement.textContent = item;
      filesContent.appendChild(itemElement);
    });
  } else if (path.startsWith('/home/user')) {
    const userItems = ['Documents', 'Downloads', 'Pictures'];
    filesContent.innerHTML = '';
    userItems.forEach(item => {
      const itemElement = document.createElement('div');
      itemElement.classList.add('fs-item');
      itemElement.onclick = () => navigate('/home/user/' + item);
      itemElement.textContent = item;
      filesContent.appendChild(itemElement);
    });
  } else {
    // Add more file/folder logic here as needed
    console.log("Navigating to:", path); // Debugging
  }
}

function openFiles() {
  filesWindow.style.display = 'flex';
  notepadWindow.style.display = 'none';
}

function openNotepad() {
  notepadWindow.style.display = 'flex';
  filesWindow.style.display = 'none';
}

function closeFiles() {
    filesWindow.style.display = 'none';
}

function closeNotepad() {
    notepadWindow.style.display = 'none';
}


newTabLink.onclick = () => {
  const newTab = document.createElement('a');
  newTab.href = '#';
  newTab.className = 'tab';
  newTab.id = 'new-tab';
  tabs.appendChild(newTab);
  editor.innerHTML = ''; // Clear the editor for the new tab
};

for (let i = 0; i < tabs.children.length; i++) {
    tabs.children[i].onclick = () => {
        currentTabIndex = i;
        editor.textContent = localStorageData[i] || '';
    }
}


function saveTab() {
  localStorageData[currentTabIndex] = editor.innerHTML;
}

window.addEventListener('beforeunload', saveTab); // Save on close/reload

// Load from local storage on page load
if (JSON.stringify(localStorageData) !== '{}') {
    localStorageData = JSON.parse(localStorageData);
    for (let i = 0; i < tabs.children.length; i++) {
        if (localStorageData[i]) {
            editor.innerHTML = localStorageData[i];
        }
    }
}

</script>

</body>
</html>
